import boto3

def create_sns_subscription(topic, endpoint):
    sns_client = boto3.client('sns')
    response = sns_client.subscribe(
        TopicArn=topic,
        Protocol='https',
        Endpoint=endpoint
    )
    return response

def main():
    topic = input("Enter the SNS Topic ARN: ")
    endpoint = input("Enter the subscription endpoint (URL): ")
    response = create_sns_subscription(topic, endpoint)
    print(response)

if __name__ == "__main__":
    main()